156	  }
157	
158	  const thiefAbility = evaluateThiefEscapeAbility(state, enemy, rng);
159	  if (thiefAbility !== null) {
160	    return thiefAbility;
161	  }
162	
163	  for (const behavior of enemy.definition.behaviors) {
164	    if (isSpecialBehavior(behavior)) {
165	      return evaluateSpecialBehavior(state, enemy, behavior, rng);
166	    }
167	
168	    if (
169	      hasBehavior(enemy, "caster") &&
